        res = []
        x = 0
        y = 0
        while True:
            if maze[x][y] == 1:
                res.pop()
                if x > 0:
                    x -= 1
                elif y > 0:
                    y -= 1
                    x -= 1
                else:
                    break
            else:
                res.append(maze[x][y])
                if y + 1 < len(maze[0]) and maze[x][y + 1] == 0:
                    y += 1
                elif x + 1 < len(maze) and maze[x + 1][y] == 0:
                    x += 1
                else:
                    break
        if len(res) == 0:
            return [-1]
        return res

