#include <iostream>
#include <vector>
#include <string>
using namespace std;
class Solution {
public:
void solve(vector<vector<int>>& maze) {
    vector<int> res;
    int x = 0, y = 0;
    bool found = false;
    while (true) {
        if (maze[x][y] == 1) {
            if (!res.empty()) {
                res.pop_back();
            }
            if (x > 0) {
                x--;
            } else if (y > 0) {
                y--;
                x--;
            } else {
                found = true;
                break;
            }
        } else {
            if (y + 1 < maze[0].size() && maze[x][y + 1] == 0) {
                y++;
            } else if (x + 1 < maze.size() && maze[x + 1][y] == 0) {
                x++;
            } else {
                found = true;
                break;
            }
            res.push_back(maze[x][y]);
        }
    }
    if (!found) {
        cout << -1 << endl;
    } else {
        for (int i = 0; i < res.size(); i++) {
            cout << res[i];
        }
        cout << endl;
    }
}
};
int main() {
    int n;
    cin >> n;
    vector<vector<int>> maze(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> maze[i][j];
        }
    }
    Solution().solve(maze);
    return 0;
}
